export const getMockResponse = (query: string): string => {
  const q = query.toLowerCase();
  if (q.includes('risk') || q.includes('high') || q.includes('dangerous')) {
    return '**Top High-Risk Accused — Karnataka Database**\n\n' +
      accusedRecords.sort((a,b) => b.riskScore - a.riskScore).slice(0,5)
        .map((a,i) => `${i+1}. **${a.name}** — Risk: ${a.riskScore}/100 — ${a.district}${a.activeWarrant?' ⚠ WARRANT':''}`)
        .join('\n') + '\n\n**Confidence:** 95% | **Sources:** Accused database';
  }
  if (q.includes('fir') || q.includes('case') || q.includes('robbery')) {
    return '**Recent FIR Records — Karnataka**\n\n' +
      firRecords.slice(0,6).map(f => `• \`${f.firNumber}\` — ${f.crimeCategory} — ${f.policeStation} — **${f.status}**`).join('\n') +
      '\n\n**Confidence:** 98% | **Sources:** FIR database';
  }
  if (q.includes('district') || q.includes('hotspot')) {
    return '**Top Crime Districts — Karnataka**\n\n' +
      crimeStats.slice(0,5).map(d => `• **${d.district}**: ${d.count} crimes — ${d.trend} (${d.changePercent > 0 ? '+' : ''}${d.changePercent}%)`).join('\n') +
      '\n\n**Confidence:** 96% | **Sources:** District statistics';
  }
  return '**KIRAN Active** — 500 FIRs indexed | 100 accused profiles | 30 districts\n\nAsk about FIRs, accused profiles, crime hotspots, network analysis or forecasting.';
};